// ════════════════════════════════════════════════════════
// TOOL: BUSCAR SERVIÇO POR CATEGORIA
// Lista serviços de uma categoria específica
// ════════════════════════════════════════════════════════

const input = $input.item.json;
const query = input.query || '';
const organizacaoId = input.organizacao_id || input.organizacaoId;
let categoriaId = input.categoria_id || input.categoriaId;

// Tentar extrair categoria_id do query
if (!categoriaId && query) {
  const match = query.match(/(\d+)/);
  if (match) categoriaId = match[1];
}

if (!categoriaId) {
  return [{ json: { error: true, message: 'categoria_id não informado. Use a tool categoria_servicos para listar as categorias disponíveis.' } }];
}
if (!organizacaoId) {
  return [{ json: { error: true, message: 'organizacao_id não informado.' } }];
}

return [{ json: { categoria_id: categoriaId, organizacao_id: organizacaoId } }];

// Formatar lista de serviços
const items = $input.all();
const servicos = items
  .map(item => item.json)
  .filter(item => item.servico_id);

if (servicos.length === 0) {
  return [{
    json: {
      response: JSON.stringify({
        servicos: [],
        mensagem: 'Nenhum serviço encontrado nesta categoria.'
      })
    }
  }];
}

// Formatar preços
const servicosFormatados = servicos.map(s => ({
  servico_id: s.servico_id,
  nome: s.nome,
  preco: `R$ ${parseFloat(s.preco || 0).toFixed(2).replace('.', ',')}`,
  preco_valor: parseFloat(s.preco || 0),
  duracao: `${s.duracao} min`,
  duracao_minutos: s.duracao,
  descricao: s.descricao || ''
}));

return [{
  json: {
    response: JSON.stringify({
      servicos: servicosFormatados,
      total: servicosFormatados.length
    })
  }
}];
